from .base import BaseHandler


class Router:
    def __init__(self):
        self._routes = {}

    def add_route(self, path, handler):
        if not isinstance(handler, BaseHandler):
            raise TypeError(f"Handler must be a BaseHandler, got {type(handler)}")
        self._routes[path] = handler

    def resolve(self, path):
        handler = self._routes.get(path)
        if handler is None:
            raise KeyError(f"No handler for path: {path}")
        return handler

    def dispatch(self, path, request):
        handler = self.resolve(path)
        handler.before_request(request)
        try:
            response = handler.handle_request(request)
        except Exception as e:
            response = handler.error_handler(request, e)
        return handler.after_request(request, response)

