from .base import BaseHandler


class MiddlewareChain(BaseHandler):
    """Wraps a handler with middleware processing."""

    def __init__(self, handler, middlewares=None):
        self.handler = handler
        self.middlewares = middlewares or []

    def handle_request(self, request):
        # Apply middleware transforms to request
        for mw in self.middlewares:
            request = mw.before(request)
        response = self.handler.handle_request(request)
        # Apply middleware transforms to response
        for mw in reversed(self.middlewares):
            response = mw.after(request, response)
        return response

