from .router import Router
from .base import BaseHandler


class Application:
    def __init__(self):
        self.router = Router()

    def route(self, path):
        def decorator(handler_class):
            if not issubclass(handler_class, BaseHandler):
                raise TypeError("Handler must extend BaseHandler")
            self.router.add_route(path, handler_class())
            return handler_class
        return decorator

    def handle(self, path, request):
        return self.router.dispatch(path, request)

