from ..base import BaseHandler


class UserListHandler(BaseHandler):
    def __init__(self):
        self._users = [
            {"id": 1, "name": "Alice"},
            {"id": 2, "name": "Bob"},
        ]

    def handle_request(self, request):
        if request.get("method") == "POST":
            user = {"id": len(self._users) + 1, "name": request["body"]["name"]}
            self._users.append(user)
            return {"status": 201, "body": user}
        return {"status": 200, "body": self._users}


class UserDetailHandler(BaseHandler):
    def __init__(self, users_handler):
        self._users_handler = users_handler

    def handle_request(self, request):
        user_id = request.get("params", {}).get("id")
        for user in self._users_handler._users:
            if user["id"] == user_id:
                return {"status": 200, "body": user}
        return {"status": 404, "body": "Not found"}

