import json
from ..base import BaseHandler


class ApiHandler(BaseHandler):
    """JSON API handler with content negotiation."""

    def before_request(self, request):
        if "body" in request and isinstance(request["body"], str):
            request["body"] = json.loads(request["body"])
        return request

    def handle_request(self, request):
        raise NotImplementedError("Subclasses must implement handle_request")

    def after_request(self, request, response):
        if isinstance(response.get("body"), (dict, list)):
            response["content_type"] = "application/json"
        return response


class HealthCheckHandler(ApiHandler):
    def handle_request(self, request):
        return {"status": 200, "body": {"healthy": True}}

