from ..base import BaseHandler


class AuthHandler(BaseHandler):
    """Authentication handler."""

    def __init__(self, secret="default-secret"):
        self.secret = secret
        self._sessions = {}

    def handle_request(self, request):
        action = request.get("action")
        if action == "login":
            return self._login(request)
        elif action == "logout":
            return self._logout(request)
        return {"status": 400, "body": "Unknown action"}

    def _login(self, request):
        username = request.get("username")
        token = f"token_{username}_{self.secret}"
        self._sessions[token] = username
        return {"status": 200, "body": {"token": token}}

    def _logout(self, request):
        token = request.get("token")
        if token in self._sessions:
            del self._sessions[token]
        return {"status": 200, "body": "Logged out"}

    def before_request(self, request):
        token = request.get("token")
        if token and token in self._sessions:
            request["user"] = self._sessions[token]
        return request

