from .base import BaseHandler


def validate_handler(obj):
    """Validate that obj is a proper handler."""
    if not isinstance(obj, BaseHandler):
        raise TypeError(f"Expected BaseHandler instance, got {type(obj).__name__}")
    if type(obj).handle_request is BaseHandler.handle_request:
        raise ValueError(f"{type(obj).__name__} does not override handle_request")
    return True


def handler_info(handler):
    """Return info dict about a handler."""
    return {
        "class": type(handler).__name__,
        "is_handler": isinstance(handler, BaseHandler),
        "has_before": type(handler).before_request is not BaseHandler.before_request,
        "has_after": type(handler).after_request is not BaseHandler.after_request,
    }
